const search = async (keyword: string, isDesktop: boolean): Promise<void> => {
	if (!keyword) {
		setPanelVisibility(false, isDesktop);
		result = [];
		return;
	}

	if (!initialized) {
		return;
	}

	isSearching = true;

	try {
		let searchResults: SearchResult[] = [];

		if (import.meta.env.PROD && pagefindLoaded && window.pagefind) {
			const response = await window.pagefind.search(keyword);
			searchResults = await Promise.all(
				response.results.map((item) => item.data()),
			);
		} else if (import.meta.env.DEV) {
			searchResults = fakeResult;
		} else {
			searchResults = [];
			console.error("Pagefind is not available in production environment.");
		}

		result = searchResults;
		setPanelVisibility(result.length > 0, isDesktop);
	} catch (error) {
		console.error("Search error:", error);
		result = [];
		setPanelVisibility(false, isDesktop);
	} finally {
		isSearching = false;
	}
};

export function inferSourceFormat(src: string): string | undefined {
	// data: URIs encode the MIME type directly, e.g. "data:image/svg+xml;base64,..."
	// or "data:image/svg+xml,<svg>...</svg>" (no media-type parameter).
	if (src.startsWith(DATA_PREFIX)) {
		const sepIndex = src.indexOf(';');
		const commaIndex = src.indexOf(',');
		const mimeEnd =
			sepIndex === -1 ? commaIndex : commaIndex === -1 ? sepIndex : Math.min(sepIndex, commaIndex);
		if (mimeEnd === -1) return undefined;
		const mime = src.slice(DATA_PREFIX.length, mimeEnd);
		if (mime === 'image/svg+xml') return 'svg';
		const sub = mime.split('/')[1];
		return sub || undefined;
	}

	// For regular URLs/paths, extract the extension from the last path segment only.
	// Looking at the whole string would treat dots in hostnames (`example.com`) as extensions.
	try {
		const cleanSrc = removeQueryString(src).split('#')[0];
		const lastSlash = cleanSrc.lastIndexOf('/');
		const basename = lastSlash === -1 ? cleanSrc : cleanSrc.slice(lastSlash + 1);
		const lastDot = basename.lastIndexOf('.');
		if (lastDot === -1) return undefined;
		return basename.slice(lastDot + 1).toLowerCase();
	} catch {
		return undefined;
	}
}

export const applyGetPermalinks = (menu: unknown = {}): unknown => {
  if (Array.isArray(menu)) {
    return menu.map((item) => applyGetPermalinks(item));
  } else if (typeof menu === 'object' && menu !== null) {
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(menu)) {
      if (key === 'href') {
        if (typeof value === 'string') {
          result[key] = getPermalink(value);
        } else if (typeof value === 'object' && value !== null) {
          const href = value as MenuHref;
          if (href.type === 'home') {
            result[key] = getHomePermalink();
          } else if (href.type === 'blog') {
            result[key] = getBlogPermalink();
          } else if (href.type === 'asset') {
            result[key] = getAsset(href.url ?? '');
          } else if (href.url) {
            result[key] = getPermalink(href.url, href.type);
          }
        }
      } else {
        result[key] = applyGetPermalinks(value);
      }
    }
    return result;
  }
  return menu;
};

handle(state: FetchState): Response | undefined {
	// Use a fresh URL parse from the raw request so we see the
	// un-normalized pathname (e.g. duplicate slashes like `///`).
	// state.url has already been normalized by the FetchState
	// constructor, which would hide the redirect targets.
	const url = new URL(state.request.url);
	const redirect = this.#redirectTrailingSlash(url.pathname);

	// Not a redirect.
	if (redirect === url.pathname) {
		return undefined;
	}

	const addCookieHeader = state.renderOptions.addCookieHeader;
	const status = state.request.method === 'GET' ? 301 : 308;
	const response = new Response(
		redirectTemplate({
			status,
			relativeLocation: url.pathname,
			absoluteLocation: redirect,
			from: state.request.url,
		}),
		{
			status,
			headers: {
				location: redirect + url.search,
			},
		},
	);
	prepareResponse(response, { addCookieHeader });
	return response;
}

export const is = {
	parent(node: Node): node is ParentNode {
		return Array.isArray((node as any).children);
	},
	literal(node: Node): node is LiteralNode {
		return typeof (node as any).value === 'string';
	},
	tag(node: Node): node is TagLikeNode {
		return (
			node.type === 'element' ||
			node.type === 'custom-element' ||
			node.type === 'component' ||
			node.type === 'fragment'
		);
	},
	whitespace(node: Node): node is TextNode {
		return node.type === 'text' && node.value.trim().length === 0;
	},
	root: guard<RootNode>('root'),
	element: guard<ElementNode>('element'),
	customElement: guard<CustomElementNode>('custom-element'),
	component: guard<ComponentNode>('component'),
	fragment: guard<FragmentNode>('fragment'),
	expression: guard<ExpressionNode>('expression'),
	text: guard<TextNode>('text'),
	doctype: guard<DoctypeNode>('doctype'),
	comment: guard<CommentNode>('comment'),
	frontmatter: guard<FrontmatterNode>('frontmatter'),
};

function updateTutorialPagination(starlightRoute: StarlightRouteData) {
	const { entry, locale, pagination } = starlightRoute;

	if (!isTutorialEntry(entry)) return;

	const tutorialPages = getTutorialPages(pages, locale!);
	const i = tutorialPages.findIndex((p) => p.id === entry.id);

	if (tutorialPages[i - 1]) {
		const prevPage = tutorialPages[i - 1];

		pagination.prev = {
			href: `/${locale}/${stripLangFromSlug(prevPage.id)}/`,
			isCurrent: false,
			label: prevPage.data.title,
			type: 'link',
			badge: undefined,
			attrs: {},
		};
	}

	if (tutorialPages[i + 1]) {
		const nextPage = tutorialPages[i + 1];

		pagination.next = {
			href: `/${locale}/${stripLangFromSlug(nextPage.id)}/`,
			isCurrent: false,
			label: nextPage.data.title,
			type: 'link',
			badge: undefined,
			attrs: {},
		};
	}
}

function isTutorialEntry(entry: StarlightRouteData['entry']) {
	return entry.id.split('/')[1] === 'tutorial';
}

export function remarkFallbackLang(): Plugin<[], Root> {
	const pageSourceDir = path.resolve('./src/content/docs');
	const baseUrl = 'https://docs.astro.build/';

	const transformer: Transformer<Root> = (tree, file) => {
		const pageUrl = mdFilePathToUrl(file.path, pageSourceDir, baseUrl);
		const pageLang = getLanguageCodeFromPathname(pageUrl.pathname);

		// Ignore pages without language prefix and English pages
		if (!pageLang || pageLang === 'en') return;

		visit(tree, 'link', (link) => {
			const linkUrl = new URL(link.url, pageUrl);

			// Ignore external links
			if (pageUrl.host !== linkUrl.host) return;

			// Ignore link targets without language prefix
			const linkLang = getLanguageCodeFromPathname(linkUrl.pathname);
			if (!linkLang) return;

			// Ignore link targets that have a valid source file
			const linkSourceFileName = tryFindSourceFileForPathname(linkUrl.pathname, pageSourceDir);
			if (linkSourceFileName) return;

			link.children.push({
				type: 'text',
				value: `\u00A0(EN)`,
			});
		});
	};

	return function attacher() {
		return transformer;
	};
}

onMount(() => {
	const initializeSearch = () => {
		initialized = true;
		pagefindLoaded =
			typeof window !== "undefined" &&
			!!window.pagefind &&
			typeof window.pagefind.search === "function";
		console.log("Pagefind status on init:", pagefindLoaded);
		if (keywordDesktop) search(keywordDesktop, true);
		if (keywordMobile) search(keywordMobile, false);
	};

	if (import.meta.env.DEV) {
		console.log(
			"Pagefind is not available in development mode. Using mock data.",
		);
		initializeSearch();
	} else {
		document.addEventListener("pagefindready", () => {
			console.log("Pagefind ready event received.");
			initializeSearch();
		});
		document.addEventListener("pagefindloaderror", () => {
			console.warn(
				"Pagefind load error event received. Search functionality will be limited.",
			);
			initializeSearch(); // Initialize with pagefindLoaded as false
		});

		// Fallback in case events are not caught or pagefind is already loaded by the time this script runs
		setTimeout(() => {
			if (!initialized) {
				console.log("Fallback: Initializing search after timeout.");
				initializeSearch();
			}
		}, 2000); // Adjust timeout as needed
	}
});

async function recursiveFetch(endpoint: string, page = 1): Promise<Contributor[]> {
	const contributors: Contributor[] = [];
	try {
		const queryParam = endpoint.includes('?') ? '&' : '?';
		const pageSize = 100;
		const url = `https://api.github.com/${endpoint}${queryParam}per_page=${pageSize}&page=${page}`;

		const token = process.env.GITHUB_TOKEN ?? '';

		const res = await fetch(url, {
			method: 'GET',
			headers: {
				Authorization: token && `Basic ${Buffer.from(token, 'binary').toString('base64')}`,
				'User-Agent': 'astro-docs/1.0',
			},
		});

		const data = await res.json();

		if (!res.ok) {
			throw new Error(
				`Request to fetch endpoint failed. Reason: ${res.statusText}
         Message: ${data?.message}`
			);
		}

		contributors.push(
			...data.map((contributor: Contributor) => ({
				id: contributor.id,
				login: contributor.login,
			}))
		);

		// Fetch more data recursively if there are more than GitHub’s per-page response limit.
		if (data.length === pageSize) {
			const rest = await recursiveFetch(endpoint, page + 1);
			contributors.push(...rest);
		}

		return contributors;
	} catch (error) {
		console.error(
			`[error]  /scripts/weekly-contributors.ts\n         ${error instanceof Error ? error.message : String(error)}`
		);
		return [];
	}
}

async ({ params, request, locals }) => {
	const { emdash, user } = locals;
	const denied = requirePerm(user, "bylines:manage");
	if (denied) return denied;

	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;

	const body = await parseBody(request, bylineUpdateBody);
	if (isParseError(body)) return body;

	const result = await handleBylineUpdate(emdash.db, params.id!, {
		slug: body.slug,
		displayName: body.displayName,
		bio: body.bio ?? null,
		avatarMediaId: body.avatarMediaId ?? null,
		websiteUrl: body.websiteUrl ?? null,
		userId: body.userId ?? null,
		isGuest: body.isGuest,
		// Forward `customFields` only when present so the repo treats an
		// omitted key as "leave existing values untouched". An empty
		// object also no-ops by repo convention — see
		// `BylineRepository.update`. Validation (unknown slug, type
		// mismatch, select-choice) happens inside the repo and surfaces
		// as `EmDashValidationError`, which the handler maps to a 400
		// `VALIDATION_ERROR` for `unwrapResult` / `mapErrorStatus`.
		customFields: body.customFields,
	});

	if (result.success) invalidateBylineCache();
	return unwrapResult(result);
}

async ({ params, locals }) => {
	const { emdash, user } = locals;
	const { id } = params;

	if (!emdash?.db) {
		return apiError("NOT_CONFIGURED", "EmDash is not initialized", 500);
	}

	const denied = requirePerm(user, "plugins:manage");
	if (denied) return denied;

	if (!id) {
		return apiError("INVALID_REQUEST", "Plugin ID required", 400);
	}

	const result = await handlePluginEnable(emdash.db, emdash.configuredPlugins, id);

	if (!result.success) return unwrapResult(result);

	// If this is a runtime-installed plugin (marketplace or registry),
	// the sandbox bundle may not be in memory yet -- a sync reloads it
	// from R2 so the just-enabled plugin can actually run hooks.
	const source = result.data.item.source;
	if (source === "registry") {
		await emdash.syncRegistryPlugins();
	} else if (source === "marketplace") {
		await emdash.syncMarketplacePlugins();
	}

	await emdash.setPluginStatus(id, "active");
	await setCronTasksEnabled(emdash.db, id, true);

	return unwrapResult(result);
}

async ({ params, request, locals, cache }) => {
	const { emdash, user } = locals;
	const collection = params.collection!;
	const id = params.id!;
	const body = await parseBody(request, contentScheduleBody);
	if (isParseError(body)) return body;

	if (!emdash?.handleContentSchedule || !emdash?.handleContentGet) {
		return apiError("NOT_CONFIGURED", "EmDash is not initialized", 500);
	}

	// Fetch item to check ownership
	const existing = await emdash.handleContentGet(collection, id);
	if (!existing.success) {
		return apiError(
			existing.error?.code ?? "UNKNOWN_ERROR",
			existing.error?.message ?? "Unknown error",
			mapErrorStatus(existing.error?.code),
		);
	}

	const { authorId, resolvedId } = extractOwnership(existing.data);
	const denied = requireOwnerPerm(user, authorId, "content:publish_own", "content:publish_any");
	if (denied) return denied;

	const result = await emdash.handleContentSchedule(collection, resolvedId ?? id, body.scheduledAt);

	if (!result.success) return unwrapResult(result);

	if (cache?.enabled) await cache.invalidate({ tags: [collection, resolvedId ?? id] });

	return unwrapResult(result);
}

